<h1><span class="mdi mdi-file-document-outline icon-blue"></span>Invoices</h1><p><a class="button" href="<?=route('invoice_new')?>"><span class="mdi mdi-plus"></span> New invoice</a></p>
<table><tr><th>Date</th><th>#</th><th>Customer</th><th>Total</th><th>Paid</th><th>Status</th><th>Record payment</th><th>Actions</th></tr><?php foreach($invoices as $i): $hasPayment=(int)($i['payment_count']??0)>0; ?><tr><td><?=h($i['invoice_date'])?></td><td><?=h($i['invoice_number'])?></td><td><?=h($i['customer_name'])?></td><td><?=$this->money($i['total'])?></td><td><?=$this->money($i['paid_amount'] ?? 0)?></td><td><?=h($i['status'])?></td><td><?php if(!$hasPayment && $i['status']!=='paid'):?><form method="post" action="<?=route('invoice_pay')?>" class="inline"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$i['id']?>"><input type="date" name="payment_date" value="<?=date('Y-m-d')?>"><input name="amount" value="<?=h($i['total'])?>"><button><span class="mdi mdi-cash-check icon-green"></span> Pay</button></form><?php else:?><span class="muted">Payment recorded</span><?php endif;?></td><td><a href="<?=route('invoice_print')?>&id=<?=$i['id']?>" target="_blank"><span class="mdi mdi-printer icon-green"></span> Print</a> <?php if(!$hasPayment):?><a href="<?=route('invoice_edit')?>&id=<?=$i['id']?>"><span class="mdi mdi-pencil icon-blue"></span> Edit</a><?php else:?><span class="muted"><span class="mdi mdi-lock-outline"></span> Locked</span><?php endif;?> <form method="post" action="<?=route('invoice_delete')?>" class="inline" onsubmit="return confirm('Delete this invoice and related ledger entries/payments?');"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=$i['id']?>"><button><span class="mdi mdi-delete icon-red"></span> Delete</button></form></td></tr><?php endforeach;?></table>
